// components/ChatbotInterface.jsx - COMPLETE ENHANCED VERSION
import React, { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import {
  MessageCircle,
  X,
  Send,
  Trash2,
  RefreshCw,
  User,
  Bot,
  AlertCircle,
  CheckCircle,
  Sparkles,
  ChevronDown,
  ChevronUp,
  Clock,
  BookOpen,
  Calendar,
  DollarSign,
  TrendingUp
} from 'lucide-react';
import './ERPChatBot.css'
// Create axios instance
const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || 'http://localhost:65000',
  withCredentials: true,
  timeout: 15000
});

const ChatbotInterface = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [sessionId, setSessionId] = useState(null);
  const [userInfo, setUserInfo] = useState(null);
  const [isCheckingAuth, setIsCheckingAuth] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState('disconnected');
  const [isExpanded, setIsExpanded] = useState(false);
  const [showQuickActions, setShowQuickActions] = useState(true);
  const [chatHistory, setChatHistory] = useState([]);
  
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);
  const messagesContainerRef = useRef(null);

  // Initialize
  useEffect(() => {
    checkAuthStatus();
    loadSavedData();
    loadChatHistory();
    
    // Auto-open for unread messages
    const hasUnread = localStorage.getItem('chatbot_has_unread');
    if (hasUnread === 'true') {
      setIsOpen(true);
      localStorage.removeItem('chatbot_has_unread');
    }
    
    // Check connection on mount
    checkConnection();
  }, []);

  // Auto-scroll
  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  // Save messages to localStorage
  useEffect(() => {
    if (messages.length > 0) {
      try {
        const messagesToSave = messages.slice(-50); // Keep last 50 messages
        localStorage.setItem('chatbot_messages', JSON.stringify(messagesToSave));
      } catch (error) {
        console.error('Error saving messages:', error);
      }
    }
  }, [messages]);

  // Check connection status
  const checkConnection = async () => {
    try {
      const response = await api.get('/api/chatbot/health');
      if (response.data.status === 'healthy') {
        setConnectionStatus('connected');
      } else {
        setConnectionStatus('error');
      }
    } catch (error) {
      setConnectionStatus('disconnected');
    }
  };

  // Check authentication status
  const checkAuthStatus = async () => {
    setIsCheckingAuth(true);
    try {
      const response = await api.get('/api/auth/me');
      if (response.data?.user) {
        const userData = response.data.user;
        const userInfoObj = {
          id: userData._id,
          role: userData.role,
          studentId: userData.studentId || userData.username || 'unknown',
          email: userData.email || userData.universityEmail,
          name: userData.fullName || `${userData.firstName || ''} ${userData.lastName || ''}`.trim(),
          firstName: userData.firstName,
          profilePic: userData.profilePic
        };
        
        setUserInfo(userInfoObj);
        
        // Store in localStorage for persistence
        localStorage.setItem('userInfo', JSON.stringify(userInfoObj));
        
        // Check chatbot availability
        try {
          const statusRes = await api.get('/api/chatbot/status');
          console.log('Chatbot status:', statusRes.data);
        } catch (statusErr) {
          console.log('Status check failed:', statusErr.message);
        }
      }
    } catch (error) {
      console.log('Auth check failed:', error.message);
      
      // Fallback to localStorage
      const stored = localStorage.getItem('userInfo');
      if (stored) {
        try {
          const userData = JSON.parse(stored);
          setUserInfo({
            ...userData,
            name: userData.fullName || `${userData.firstName || ''} ${userData.lastName || ''}`.trim()
          });
        } catch (e) {
          console.error('Error parsing stored user info:', e);
        }
      }
    } finally {
      setIsCheckingAuth(false);
    }
  };

  // Load saved data
  const loadSavedData = () => {
    try {
      // Load messages
      const savedMessages = localStorage.getItem('chatbot_messages');
      if (savedMessages) {
        const parsed = JSON.parse(savedMessages);
        setMessages(parsed);
      }
      
      // Load session ID
      const savedSessionId = localStorage.getItem('chatbotSessionId');
      if (savedSessionId) {
        setSessionId(savedSessionId);
      }
    } catch (error) {
      console.error('Error loading saved data:', error);
    }
  };

  // Load chat history from API
  const loadChatHistory = async () => {
    if (!userInfo?.studentId) return;
    
    try {
      const response = await api.get('/api/chatbot/history');
      if (response.data.success) {
        setChatHistory(response.data.data || []);
      }
    } catch (error) {
      console.error('Error loading chat history:', error);
    }
  };

  // Send message
  const handleSendMessage = async (e) => {
    e.preventDefault();
    
    const message = inputMessage.trim();
    if (!message || isLoading || !userInfo) return;
    
    // Add user message
    const userMessage = {
      id: Date.now(),
      text: message,
      sender: 'user',
      timestamp: new Date().toISOString(),
      displayTime: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    
    setMessages(prev => [...prev, userMessage]);
    setInputMessage('');
    setIsLoading(true);
    
    try {
      console.log('Sending message to chatbot...');
      
      const response = await api.post('/api/chatbot/chat', {
        message: message,
        sessionId: sessionId
      });

      console.log('Chatbot response:', response.data);

      if (response.data.success) {
        // Update session ID if new
        if (response.data.sessionId && response.data.sessionId !== sessionId) {
          setSessionId(response.data.sessionId);
          localStorage.setItem('chatbotSessionId', response.data.sessionId);
        }
        
        // Add bot response
        const botMessage = {
          id: Date.now() + 1,
          text: response.data.response,
          sender: 'bot',
          timestamp: new Date().toISOString(),
          displayTime: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          metadata: response.data.metadata,
          isError: false
        };
        
        setMessages(prev => [...prev, botMessage]);
        setConnectionStatus('connected');
        
        // Load updated history
        if (isOpen) {
          setTimeout(loadChatHistory, 500);
        }
      } else {
        throw new Error(response.data.message || 'Chatbot returned an error');
      }
    } catch (error) {
      console.error('Chat error:', error);
      
      let errorMessage = "I'm having trouble connecting right now. Please try again.";
      
      if (error.response) {
        switch (error.response.status) {
          case 401:
            errorMessage = "Please log in to use the chatbot.";
            setUserInfo(null);
            localStorage.removeItem('userInfo');
            break;
          case 403:
            errorMessage = "Chatbot is only available for students.";
            break;
          case 429:
            errorMessage = "Too many requests. Please wait a moment.";
            break;
          case 500:
            errorMessage = "Server error. Please try again later.";
            break;
          default:
            errorMessage = error.response.data?.message || "Something went wrong.";
        }
      } else if (error.request) {
        errorMessage = "Cannot connect to the server. Please check your internet connection.";
        setConnectionStatus('disconnected');
      }
      
      // Add error message
      const errorMsg = {
        id: Date.now() + 1,
        text: errorMessage,
        sender: 'system',
        timestamp: new Date().toISOString(),
        displayTime: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        isError: true
      };
      
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
      setTimeout(() => {
        inputRef.current?.focus();
        scrollToBottom();
      }, 100);
    }
  };

  // Quick action handler
  const handleQuickAction = (action) => {
    setInputMessage(action.text);
    setTimeout(() => {
      if (inputRef.current) {
        inputRef.current.focus();
        inputRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
    }, 50);
  };

  // Clear chat
  const handleClearChat = async () => {
    if (!window.confirm('Are you sure you want to clear all chat history?')) return;
    
    if (sessionId) {
      try {
        await api.delete('/api/chatbot/clear', {
          data: { sessionId: sessionId }
        });
      } catch (error) {
        console.error('Error clearing server history:', error);
      }
    }
    
    setMessages([]);
    setSessionId(null);
    localStorage.removeItem('chatbot_messages');
    localStorage.removeItem('chatbotSessionId');
    
    // Add system message
    const systemMsg = {
      id: Date.now(),
      text: "Chat history cleared. How can I help you today?",
      sender: 'system',
      timestamp: new Date().toISOString(),
      displayTime: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    
    setMessages([systemMsg]);
  };

  // Refresh auth status
  const refreshAuthStatus = async () => {
    await checkAuthStatus();
    if (userInfo) {
      addSystemMessage("User information refreshed. You can now ask questions.");
    }
  };

  // Add system message
  const addSystemMessage = (text) => {
    const systemMsg = {
      id: Date.now(),
      text: text,
      sender: 'system',
      timestamp: new Date().toISOString(),
      displayTime: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    
    setMessages(prev => [...prev, systemMsg]);
    scrollToBottom();
  };

  // Scroll to bottom
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // Format date for history
  const formatHistoryDate = (dateString) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffTime = Math.abs(now - date);
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
    
    if (diffDays === 0) return 'Today';
    if (diffDays === 1) return 'Yesterday';
    if (diffDays < 7) return `${diffDays} days ago`;
    if (diffDays < 30) return `${Math.floor(diffDays / 7)} weeks ago`;
    return date.toLocaleDateString();
  };

  // Load conversation from history
  const loadConversation = (session) => {
    if (session.messages && session.messages.length > 0) {
      const formattedMessages = session.messages.map(msg => ({
        id: Date.now() + Math.random(),
        text: msg.content,
        sender: msg.role === 'user' ? 'user' : 'bot',
        timestamp: msg.timestamp,
        displayTime: new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }));
      
      setMessages(formattedMessages);
      setSessionId(session.sessionId);
      localStorage.setItem('chatbotSessionId', session.sessionId);
      scrollToBottom();
    }
  };

  // Quick actions
  const quickActions = [
    {
      text: "What's my current fee due?",
      icon: <DollarSign size={16} />,
      category: "fees"
    },
    {
      text: "Show today's timetable",
      icon: <Calendar size={16} />,
      category: "schedule"
    },
    {
      text: "My attendance in current courses",
      icon: <TrendingUp size={16} />,
      category: "attendance"
    },
    {
      text: "What are my exam results?",
      icon: <BookOpen size={16} />,
      category: "results"
    },
    {
      text: "Upcoming university events",
      icon: <Calendar size={16} />,
      category: "events"
    },
    {
      text: "Show my enrolled courses",
      icon: <BookOpen size={16} />,
      category: "courses"
    },
    {
      text: "What's my CGPA?",
      icon: <TrendingUp size={16} />,
      category: "academics"
    },
    {
      text: "Pending assignments",
      icon: <Clock size={16} />,
      category: "assignments"
    }
  ];

  // Connection status indicator
  const getConnectionStatus = () => {
    switch (connectionStatus) {
      case 'connected':
        return {
          text: 'Connected',
          color: 'bg-green-500',
          icon: <CheckCircle size={12} />
        };
      case 'disconnected':
        return {
          text: 'Disconnected',
          color: 'bg-red-500',
          icon: <AlertCircle size={12} />
        };
      default:
        return {
          text: 'Connecting...',
          color: 'bg-yellow-500',
          icon: <RefreshCw size={12} className="animate-spin" />
        };
    }
  };

  const connectionStatusData = getConnectionStatus();

  // Render welcome message when no messages
  if (messages.length === 0 && isOpen) {
    const welcomeMessage = {
      id: 1,
      text: `Hello${userInfo?.firstName ? ` ${userInfo.firstName}` : ''}! I'm your ERP Assistant. I can help you with:\n\n• Fees and payments\n• Attendance tracking\n• Timetable and schedule\n• Exam results\n• Course information\n• University events\n\nTry asking a question or use one of the quick actions below!`,
      sender: 'bot',
      timestamp: new Date().toISOString(),
      displayTime: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    
    setMessages([welcomeMessage]);
  }

  return (
    <>
      {/* Floating Chat Button */}
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className="fixed bottom-6 right-6 z-50 w-14 h-14 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-full shadow-2xl flex items-center justify-center hover:scale-105 transition-all duration-200 group"
          aria-label="Open chatbot"
        >
          <div className="relative">
            <MessageCircle className="w-7 h-7 text-white" />
            {connectionStatus === 'connected' && userInfo && (
              <span className="absolute -top-1 -right-1 w-3 h-3 bg-green-400 rounded-full border-2 border-white"></span>
            )}
          </div>
          <div className="absolute -top-10 right-0 bg-gray-800 text-white text-sm px-3 py-1 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
            ERP Assistant
          </div>
        </button>
      )}

      {/* Chat Window */}
      {isOpen && (
        <div className={`fixed z-50 right-6 ${isExpanded ? 'bottom-6 w-[800px] h-[85vh]' : 'bottom-6 w-[400px] h-[600px]'} bg-white rounded-2xl shadow-2xl flex flex-col overflow-hidden transition-all duration-300`}>
          
          {/* Header */}
          <div className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white p-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="relative">
                  <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center">
                    <Bot className="w-6 h-6" />
                  </div>
                  <div className={`absolute -bottom-1 -right-1 w-4 h-4 ${connectionStatusData.color} rounded-full border-2 border-white flex items-center justify-center`}>
                    {connectionStatusData.icon}
                  </div>
                </div>
                <div>
                  <h3 className="font-bold text-lg">ERP Assistant</h3>
                  <div className="flex items-center gap-2 text-sm opacity-90">
                    <span className="flex items-center gap-1">
                      {connectionStatusData.text}
                    </span>
                    {userInfo?.studentId && (
                      <>
                        <span className="opacity-50">•</span>
                        <span className="bg-white/20 px-2 py-0.5 rounded-full text-xs">
                          {userInfo.studentId}
                        </span>
                      </>
                    )}
                  </div>
                </div>
              </div>
              
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setIsExpanded(!isExpanded)}
                  className="p-2 hover:bg-white/20 rounded-lg transition"
                  title={isExpanded ? 'Collapse' : 'Expand'}
                >
                  {isExpanded ? <ChevronDown size={20} /> : <ChevronUp size={20} />}
                </button>
                <button
                  onClick={() => setIsOpen(false)}
                  className="p-2 hover:bg-white/20 rounded-lg transition"
                  title="Close"
                >
                  <X size={20} />
                </button>
              </div>
            </div>
          </div>

          {/* Main Content */}
          <div className="flex flex-1 overflow-hidden">
            {/* Chat History Sidebar (Visible when expanded) */}
            {isExpanded && (
              <div className="w-64 border-r border-gray-200 flex flex-col">
                <div className="p-4 border-b border-gray-200">
                  <h4 className="font-semibold text-gray-700 flex items-center gap-2">
                    <Clock size={16} />
                    Chat History
                  </h4>
                </div>
                <div className="flex-1 overflow-y-auto p-2">
                  {chatHistory.length === 0 ? (
                    <div className="text-center py-8 text-gray-500 text-sm">
                      <Clock className="w-8 h-8 mx-auto mb-2 opacity-50" />
                      <p>No previous conversations</p>
                    </div>
                  ) : (
                    chatHistory.map((session, index) => (
                      <button
                        key={session.sessionId || index}
                        onClick={() => loadConversation(session)}
                        className="w-full text-left p-3 rounded-lg hover:bg-gray-100 transition mb-2"
                      >
                        <div className="flex items-center justify-between mb-1">
                          <span className="font-medium text-sm text-gray-700">
                            Session {index + 1}
                          </span>
                          <span className="text-xs text-gray-500">
                            {formatHistoryDate(session.updatedAt)}
                          </span>
                        </div>
                        <div className="text-xs text-gray-500 truncate">
                          {session.messages?.slice(-1)[0]?.content || 'No messages'}
                        </div>
                        <div className="flex items-center gap-2 mt-2">
                          <span className="text-xs px-2 py-1 bg-blue-100 text-blue-700 rounded-full">
                            {session.messageCount} messages
                          </span>
                          {session.lastIntent && (
                            <span className="text-xs px-2 py-1 bg-gray-100 text-gray-700 rounded-full truncate">
                              {session.lastIntent}
                            </span>
                          )}
                        </div>
                      </button>
                    ))
                  )}
                </div>
              </div>
            )}

            {/* Chat Area */}
            <div className="flex-1 flex flex-col">
              {/* Messages Container */}
              <div
                ref={messagesContainerRef}
                className="flex-1 overflow-y-auto p-4 bg-gray-50"
              >
                {!userInfo ? (
                  // Not logged in state
                  <div className="h-full flex flex-col items-center justify-center p-8 text-center">
                    <div className="w-16 h-16 bg-yellow-100 rounded-full flex items-center justify-center mb-4">
                      <AlertCircle className="w-8 h-8 text-yellow-600" />
                    </div>
                    <h3 className="text-lg font-semibold text-gray-800 mb-2">
                      Authentication Required
                    </h3>
                    <p className="text-gray-600 mb-6">
                      Please log in to access the chatbot features.
                    </p>
                    <div className="flex flex-col gap-3 w-full max-w-xs">
                      <button
                        onClick={() => window.location.href = '/login'}
                        className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition font-medium"
                      >
                        Go to Login
                      </button>
                      <button
                        onClick={refreshAuthStatus}
                        className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition flex items-center justify-center gap-2"
                      >
                        <RefreshCw size={16} />
                        Refresh Status
                      </button>
                    </div>
                  </div>
                ) : messages.length === 0 ? (
                  // Loading state
                  <div className="h-full flex items-center justify-center">
                    <div className="text-center">
                      <div className="w-12 h-12 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mx-auto mb-4"></div>
                      <p className="text-gray-600">Loading chatbot...</p>
                    </div>
                  </div>
                ) : (
                  // Messages
                  <div className="space-y-4">
                    {messages.map((message) => (
                      <div
                        key={message.id}
                        className={`flex gap-3 ${message.sender === 'user' ? 'justify-end' : 'justify-start'}`}
                      >
                        {message.sender === 'bot' && (
                          <div className="flex-shrink-0 w-8 h-8 bg-gradient-to-r from-blue-500 to-indigo-500 rounded-full flex items-center justify-center">
                            <Bot className="w-4 h-4 text-white" />
                          </div>
                        )}
                        
                        {message.sender === 'system' && (
                          <div className="flex-shrink-0 w-8 h-8 bg-yellow-100 rounded-full flex items-center justify-center">
                            <AlertCircle className="w-4 h-4 text-yellow-600" />
                          </div>
                        )}
                        
                        <div
                          className={`max-w-[80%] rounded-2xl px-4 py-3 ${
                            message.sender === 'user'
                              ? 'bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-br-none'
                              : message.sender === 'system'
                              ? 'bg-yellow-50 border border-yellow-100 text-yellow-800'
                              : message.isError
                              ? 'bg-red-50 border border-red-100 text-red-800'
                              : 'bg-white border border-gray-200 text-gray-800 shadow-sm'
                          }`}
                        >
                          <div className="whitespace-pre-wrap text-sm">
                            {message.text}
                          </div>
                          <div className={`text-xs mt-2 flex items-center justify-between ${
                            message.sender === 'user' ? 'text-blue-200' : 'text-gray-500'
                          }`}>
                            <span>{message.displayTime}</span>
                            {message.metadata?.intent && (
                              <span className="px-2 py-0.5 bg-gray-100 rounded-full">
                                {message.metadata.intent}
                              </span>
                            )}
                          </div>
                        </div>
                        
                        {message.sender === 'user' && (
                          <div className="flex-shrink-0 w-8 h-8 bg-gray-200 rounded-full flex items-center justify-center">
                            {userInfo.profilePic ? (
                              <img
                                src={userInfo.profilePic}
                                alt="User"
                                className="w-full h-full rounded-full object-cover"
                              />
                            ) : (
                              <User className="w-4 h-4 text-gray-600" />
                            )}
                          </div>
                        )}
                      </div>
                    ))}
                    
                    {isLoading && (
                      <div className="flex gap-3">
                        <div className="flex-shrink-0 w-8 h-8 bg-gradient-to-r from-blue-500 to-indigo-500 rounded-full flex items-center justify-center">
                          <Bot className="w-4 h-4 text-white" />
                        </div>
                        <div className="bg-white border border-gray-200 rounded-2xl px-4 py-3 rounded-bl-none">
                          <div className="flex items-center gap-2">
                            <div className="flex space-x-1">
                              <div className="w-2 h-2 bg-gray-400 rounded-full animate-pulse"></div>
                              <div className="w-2 h-2 bg-gray-400 rounded-full animate-pulse delay-100"></div>
                              <div className="w-2 h-2 bg-gray-400 rounded-full animate-pulse delay-200"></div>
                            </div>
                            <span className="text-sm text-gray-500">Thinking...</span>
                          </div>
                        </div>
                      </div>
                    )}
                    
                    <div ref={messagesEndRef} />
                  </div>
                )}
              </div>

              {/* Quick Actions */}
              {showQuickActions && userInfo && (
                <div className="border-t border-gray-200 p-3">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-sm font-medium text-gray-700">Quick Actions</span>
                    <button
                      onClick={() => setShowQuickActions(false)}
                      className="text-xs text-gray-500 hover:text-gray-700"
                    >
                      Hide
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {quickActions.slice(0, isExpanded ? 8 : 4).map((action, index) => (
                      <button
                        key={index}
                        onClick={() => handleQuickAction(action)}
                        className="inline-flex items-center gap-2 px-3 py-2 bg-blue-50 hover:bg-blue-100 text-blue-700 rounded-lg text-sm transition-colors"
                      >
                        {action.icon}
                        <span className="truncate max-w-[120px]">{action.text}</span>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Input Area */}
              <div className="border-t border-gray-200 p-4">
                {userInfo ? (
                  <form onSubmit={handleSendMessage} className="space-y-3">
                    <div className="flex gap-2">
                      <div className="flex-1 relative">
                        <textarea
                          ref={inputRef}
                          value={inputMessage}
                          onChange={(e) => setInputMessage(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && !e.shiftKey) {
                              e.preventDefault();
                              handleSendMessage(e);
                            }
                          }}
                          placeholder="Ask about fees, attendance, timetable..."
                          className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 resize-none"
                          rows="1"
                          disabled={isLoading}
                          autoFocus
                        />
                        <div className="absolute right-3 top-3 text-xs text-gray-500">
                          {inputMessage.length > 0 && `${inputMessage.length}/1000`}
                        </div>
                      </div>
                      <button
                        type="submit"
                        disabled={!inputMessage.trim() || isLoading}
                        className="px-4 py-3 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-xl hover:from-blue-700 hover:to-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center justify-center"
                      >
                        {isLoading ? (
                          <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                        ) : (
                          <Send className="w-5 h-5" />
                        )}
                      </button>
                    </div>
                    
                    <div className="flex items-center justify-between text-xs text-gray-500">
                      <div className="flex items-center gap-4">
                        <button
                          type="button"
                          onClick={handleClearChat}
                          className="flex items-center gap-1 hover:text-gray-700 transition"
                        >
                          <Trash2 size={14} />
                          Clear Chat
                        </button>
                        <button
                          type="button"
                          onClick={refreshAuthStatus}
                          className="flex items-center gap-1 hover:text-gray-700 transition"
                        >
                          <RefreshCw size={14} />
                          Refresh
                        </button>
                        <button
                          type="button"
                          onClick={() => setShowQuickActions(!showQuickActions)}
                          className="flex items-center gap-1 hover:text-gray-700 transition"
                        >
                          <Sparkles size={14} />
                          {showQuickActions ? 'Hide' : 'Show'} Actions
                        </button>
                      </div>
                      
                      <div className="flex items-center gap-2">
                        <div className="flex items-center gap-1">
                          <div className={`w-2 h-2 rounded-full ${connectionStatusData.color}`}></div>
                          <span>{connectionStatusData.text}</span>
                        </div>
                        <span className="opacity-50">•</span>
                        <span className="font-medium">{userInfo.role}</span>
                      </div>
                    </div>
                  </form>
                ) : (
                  <div className="text-center p-4">
                    <p className="text-gray-600 mb-3">Please log in to use the chatbot</p>
                    <div className="flex gap-3 justify-center">
                      <button
                        onClick={() => window.location.href = '/login'}
                        className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition text-sm font-medium"
                      >
                        Login Now
                      </button>
                      <button
                        onClick={refreshAuthStatus}
                        className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition text-sm flex items-center gap-2"
                      >
                        <RefreshCw size={14} />
                        Check Status
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* User Info Footer */}
          {userInfo && (
            <div className="border-t border-gray-200 bg-gray-50 px-4 py-2">
              <div className="flex items-center justify-between text-xs">
                <div className="flex items-center gap-2">
                  <div className="w-6 h-6 bg-gray-300 rounded-full flex items-center justify-center">
                    {userInfo.profilePic ? (
                      <img
                        src={userInfo.profilePic}
                        alt={userInfo.name}
                        className="w-full h-full rounded-full object-cover"
                      />
                    ) : (
                      <User className="w-3 h-3 text-gray-600" />
                    )}
                  </div>
                  <div>
                    <span className="font-medium text-gray-700">{userInfo.name}</span>
                    <span className="text-gray-500 ml-2">{userInfo.studentId}</span>
                  </div>
                </div>
                <div className="text-gray-500">
                  Press <kbd className="px-2 py-1 bg-gray-200 rounded text-xs">Enter</kbd> to send • <kbd className="px-2 py-1 bg-gray-200 rounded text-xs">Shift+Enter</kbd> for new line
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Styles */}
      <style jsx>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        
        @keyframes slideIn {
          from { transform: translateX(100%); }
          to { transform: translateX(0); }
        }
        
        .animate-fade-in {
          animation: fadeIn 0.3s ease-out;
        }
        
        .animate-slide-in {
          animation: slideIn 0.3s ease-out;
        }
        
        /* Custom scrollbar */
        ::-webkit-scrollbar {
          width: 6px;
        }
        
        ::-webkit-scrollbar-track {
          background: #f1f1f1;
          border-radius: 3px;
        }
        
        ::-webkit-scrollbar-thumb {
          background: #c1c1c1;
          border-radius: 3px;
        }
        
        ::-webkit-scrollbar-thumb:hover {
          background: #a1a1a1;
        }
        
        /* Textarea auto-resize */
        textarea {
          min-height: 48px;
          max-height: 120px;
        }
      `}</style>
    </>
  );
};

export default ChatbotInterface;
